function LxStoryCtrl:_InternalStartStory(storyType, storyId,closeAllView)
    if(closeAllView == nil)then
        closeAllView = true
    end
    --self:CheckMissingStory()
    if storyType == 1 then
        if not self._newbieView then
            self._newbieView = require("LApp.gameplay.newbie.view.LNewbieView"):new()
            self._newbieView:Initialize()
        end

        local newBieCfg = GameTable.StoryNewbieRef[storyId]
        if(newBieCfg == nil)then
            if LOG_INFO_ENABLED then
                printError("Story", "不存在剧情事件id="..tostring(storyId))
            end
        end

        local chapter = newBieCfg.chapter
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local begin = v.parameter
            local condition = string.split(v.type,"=")
            if(checknumber(condition[1]) == 1 and (checknumber(condition[2]) == chapter))then
                self._curTriggerRef = v;
                break
                --return 1,v.parameter
            end
        end
        self._newbieView:StartNewbie(storyId)
        FireEvent(EventNames.ON_NEWBIE_START, storyId)
        if(closeAllView)then
            MgrCenter.PanelMgr:CloseAllOrdinaryView({UiNames.ChapterSwitching})
        end

        CtrlCenter.City:HideAllPeopleHUD()
    end
end

