function LxStoryCtrl:TryContinueStory(check)
    local run = ModuleCenter.Story:IsNewbieRunning()
    if(run)then
        return
    end
    if(check)then
        self:CheckMissingStory()
    end

    local startStoryType = ModuleCenter.Story:GetStartStoryType()
    if(startStoryType == -999)then
        return false
    end
    if startStoryType == 1 then
        local resetId = self:GetNewbieResetStep(ModuleCenter.Story:GetLastSceneId())
        if resetId > 0 then
            self._tempMgr:DoRecordStory(resetId)
            self:_InternalStartStory(startStoryType, resetId)
            return true
        end
    else
        local storyType , dataId = self:CheckTrigger(NewbieTriggerType.FirstEnterGame)
        if storyType > 0 and dataId > 0 then
            self:_InternalStartStory(storyType, dataId)
            return true
        end
    end
    return false
end
---检查错过的剧情
function LxStoryCtrl:CheckMissingStory()
    local passEventList = ModuleCenter.Story:GetPassEventIds()
    local passConditionList = {}
    --通过已经完成的事件，筛出所有的已经完成的conditionID
    for i, v in ipairs(passEventList) do
        if(v ~= 0)then
            local passConditionId = self:GetEndGroupIdByEventId(v)
            if(self:CheckListDataExits(passConditionList,passConditionId) == false)then
                table.insert(passConditionList,passConditionId)
            end
        end
    end
    --在完成的conditionID里找到排序值最大的那个
    local tempId = 0
    local tempOrder = 0
    for i, v in pairs(passConditionList) do
        local config = GameTable.StorylineTriggerRef[v]
        if(config == nil)then
            return
        end
        if(config.hierarchy > tempOrder)then
            tempOrder = config.hierarchy
            tempId = config.refId
        end
    end

    --在condition表里找出所有的排序值比tempOrder小，并且是结束触发的配置
    local orderSmallessList = {}
    for i, v in pairs(GameTable.StorylineTriggerRef) do
        if(v.hierarchy < tempOrder)then
            local arr = string.split(v.type,"=")
            if(checknumber(arr[1]) == 2)then
                table.insert(orderSmallessList,v.refId)
            end
        end
    end

    --从orderSmallessList里到passConditionList里查找有没有漏掉的
    local missEndList = {}
    for i, v in pairs(orderSmallessList) do
        if(self:CheckListDataExits(passConditionList,v) == false)then
            table.insert(missEndList,v)
        end
    end
    if(#missEndList <= 0)then
        --没有漏掉的
        return
    end
    --通过结束的触发ID，匹配开始的触发ID
    local missBeginList = {}
    for i, v in pairs(missEndList) do
        local start = self:GetStartByEnd(v)
        table.insert(missBeginList,start)
    end
    --for i, v in pairs(missBeginList) do
    --    self:GMDoStory(-1)
    --end
    self:SkipStory(missBeginList)
end

function LxStoryCtrl:GetStartByEnd(endRefId)
    local endConfig = GameTable.StorylineTriggerRef[endRefId]
    local endArr = string.split(endConfig.type,"=")
    for i, v in pairs(GameTable.StorylineTriggerRef) do
        local arr = string.split(v.type,"=")
        if(checknumber(arr[1]) == 1 and checknumber(arr[2]) == checknumber(endArr[2]))then
            return v.refId
        end
    end
end
function LxStoryCtrl:CheckListDataExits(list,data)
    for i, v in pairs(list) do
        if(v == data)then
            return true
        end
    end
    return false
end
function LxStoryCtrl:GetEndGroupIdByEventId(eventId)
    local config = GameTable.StoryNewbieRef[eventId]
    if(config == nil)then
        return 0
    end
    local chapaterId = config.chapter
    for i, v in pairs(GameTable.StorylineTriggerRef) do
        local arr = string.split(v.type,"=")
        if(checknumber(arr[1]) == 2 and checknumber(arr[2]) == chapaterId)then
            return v.refId
        end
    end
    return 0
end
---检查是否有满足条件的触发(包括开始和结束)
---@param eventType NewbieTriggerType
---@param eventId id
function LxStoryCtrl:CheckTrigger(eventType,eventId)
    local run = ModuleCenter.Story:IsNewbieRunning()
    if(run == false)then
        --当前正在进行的是空的，直接检查有没有满足条件的
        --self:CheckMissingStory()
       return self:CheckTriggerStart(eventType,eventId)
    else
        if(self:CheckTriggerEnd(eventType,eventId) == false)then
            --没有结束
            return 0,0
        end
        --self:CheckMissingStory()
        if(self._curTriggerRef == nil)then
            return 0,0
        end
        local condition = string.split(self._curTriggerRef.condition,"=")
        local t = checknumber(condition[1])
        if(t == NewbieTriggerType.EndTask)then
            ShowPanel(UiNames.ChapterSwitching)
            return 0,0
        end
        --结束，通过triggerId判断有没有可以开启的
        local curGroupId = string.split(self._curTriggerRef.type,"=")[2]
        local endGroupId = self:GetEndGroupId()
        self._curTriggerRef = nil;
        local temp1,temp2 = self:CheckTriggerStart(eventType,eventId)
        if(temp1 > 0 and temp2 > 0)then
            return temp1,temp2
        end
        temp1,temp2 = self:CheckTriggerStart(NewbieTriggerType.TriggerEvent,endGroupId)
        if(temp1 > 0 and temp2 > 0)then
            return temp1,temp2
        end
    end
    return 0,0
end
---检查开启
function LxStoryCtrl:CheckTriggerStart(eventType,eventId)
    if(eventType == NewbieTriggerType.FirstEnterGame)then
        --首次登录
        if(self:CheckFirstLogin())then
            local tempTrigger = nil
            for i, v in pairs(GameTable.StorylineTriggerRef) do
                local condition = string.split(v.condition,"=")
                if(checknumber(condition[1]) == 1)then
                    self._curTriggerRef = v;
                    return 1,v.parameter
                end
            end
        end
    elseif eventType == NewbieTriggerType.BuildUpLevelUp then
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local conditionType = string.split(v.condition,"=")
            if(checknumber(conditionType[1]) == NewbieTriggerType.BuildUpLevelUp)then
                --同一个类型
                if(checknumber(conditionType[2]) == eventId)then
                    self._curTriggerRef = v;
                    return 1,v.parameter
                end
            end
        end
    elseif eventType == NewbieTriggerType.UnLockTask then

        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local conditionType = string.split(v.condition,"=")
            if(checknumber(conditionType[1]) == NewbieTriggerType.UnLockTask)then
                --同一个类型
                if(checknumber(conditionType[2]) == CtrlCenter.Quest:GetChapterTaskId())then
                    --同一个章节
                    self._curTriggerRef = v;
                    return 1,v.parameter
                end
            end
        end

    elseif eventType == NewbieTriggerType.PeopleTime then
        --限时民心任务完成，关闭界面
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local conditionType = string.split(v.condition,"=")
            if(checknumber(conditionType[1]) == NewbieTriggerType.PeopleTime)then
                --同一个类型
                local last = ModuleCenter.Quest:GetLastPeopleTime()
                local passPeopleTimeQuest = ModuleCenter.Quest:GetPeopleTimes()
                if(last == checknumber(conditionType[2]))then
                    if(passPeopleTimeQuest[checknumber(conditionType[2])] == true)then
                        --民心任务已经完成
                        self._curTriggerRef = v;
                        return 1,v.parameter
                    end
                end

            end
        end
    elseif eventType == NewbieTriggerType.CityMonster then
        --主城怪物
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local conditionType = string.split(v.condition,"=")
            if(checknumber(conditionType[1]) == NewbieTriggerType.CityMonster)then
                local arr = string.split(conditionType[2],"|")
                for a, value in pairs(arr) do
                    if(checknumber(value) == eventId)then
                        self._curTriggerRef = v;
                        return 1,v.parameter
                    end
                end

            end
        end
    elseif eventType == NewbieTriggerType.GuideEnd then
        --新手引导
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local conditionType = string.split(v.condition,"=")
            if(checknumber(conditionType[1]) == eventType and eventId == checknumber(conditionType[2]))then
                self._curTriggerRef = v;
                return 1,v.parameter
            end
        end
    else
        --其余条件
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local type = string.split(v.type,"=")
            if(checknumber(type[1]) == 1)then
                local condition = string.split(v.condition,"=")
                local count = #condition
                if(count >= 2)then
                    if(eventType == checknumber(condition[1]) and eventId == checknumber(condition[2]))then
                        self._curTriggerRef = v;
                        return 1,v.parameter
                    end
                end
            end

        end
    end
    return 0,0
end
---检查结束
function LxStoryCtrl:CheckTriggerEnd(eventType,eventId)
    if(eventType == NewbieTriggerType.FirstEnterGame)then
        return self:CheckFirstLogin();
    else
        local curTriggerEndConfig = nil
        if(self._curTriggerRef == nil)then
            return true
        end
        local curGroup = string.split(self._curTriggerRef.type,"=")
        for i, v in pairs(GameTable.StorylineTriggerRef) do
            local type = string.split(v.type,"=")
            if(checknumber(type[1]) == 2)then
                local condition = string.split(v.condition,"=")
                local num = #condition
                local group = string.split(v.type,"=")
                if(checknumber(condition[2]) == eventId and v.parameter == -1 and checknumber(group[2]) == checknumber(curGroup[2]))then
                    curTriggerEndConfig = v;
                    break;
                end
            end

        end
        if(curTriggerEndConfig == nil)then
            return false
        end
        local conditionGroup = string.split(curTriggerEndConfig.condition,"=")
        if(eventId == checknumber(conditionGroup[2]) and eventType == checknumber(conditionGroup[1]))then
            CtrlCenter.Guide:DoTrigger(1,curTriggerEndConfig.refId)
            return true
        end
    end

    return false

end

