end
function LxStoryCtrl:GMPassNext3(ids)
    while(ids ~= nil and #ids > 0)do
        local temp = {}
        for i, v in pairs(ids) do
            local cfg = GameTable.StoryNewbieRef[v]
            if(cfg ~= nil)then
                if(cfg.server == 1)then
                    HandlerCenter.Role:SceneSystemLookReq(1, {cfg.refId})
                end
                ModuleCenter.Story:AddToPass(cfg.refId)
                if(cfg.next ~= nil and cfg.next ~= "")then
                    local arr = string.split(cfg.next,",")
                    for j, value in pairs(arr) do
                        table.insert(temp,checknumber(value))
                    end
                end
            end
        end
        ids = temp
    end
end
function LxStoryCtrl:GetEndGroupId()
    local curGroupId = string.split(self._curTriggerRef.type,"=")[2]
    local endGroupId = 0
    for i, v in pairs(GameTable.StorylineTriggerRef) do
        local type = string.split(v.type,"=")
        if(checknumber(type[1]) == 2 and checknumber(type[2]) ==checknumber(curGroupId) and v.parameter == -1)then
            endGroupId = v.refId
            break
        end
    end
    return endGroupId
end
