function LxStoryCtrl:GMDoStoryEvent(eventId)
    local beginCfg = GameTable.StoryNewbieRef[eventId]
    if(beginCfg == nil)then
        return
    end
    if(self._curTriggerRef ~= nil)then
        self:RecordNewbieStep(0)
        self:OnNewBieFinished()
    end
    local chapter = beginCfg.chapter
    for i, v in pairs(GameTable.StorylineTriggerRef) do
        local arr = string.split(v.type,"=")
        if(checknumber(arr[1]) == 1 and chapter == checknumber(arr[2]))then
            self._curTriggerRef = v;
            break
        end
    end
    self._tempMgr:DoRecordStory(eventId)
    self:StartStory(eventId,false)
end
function LxStoryCtrl:GMDoStory(id)
    if(id == -1)then
        if(self._curTriggerRef == nil)then
            return
        end
        local beginCfg = GameTable.StoryNewbieRef[self._curTriggerRef.parameter]
        if(beginCfg == nil)then
            return
        end
        --self._tempMgr:DoSkipStory(beginCfg.refId)
        local skipList = self:GetNextList(beginCfg.refId)
        HandlerCenter.Role:SceneSystemLookReq(1, skipList)
        ModuleCenter.Story:AddToPass(beginCfg.refId)
        --self:GMPassNext2(beginCfg.next)
        self:RecordNewbieStep(0)
        self:OnNewBieFinished()
        ModuleCenter.Story:SetNewbieRunning(false)
        --结束，通过triggerId判断有没有可以开启的
        local curGroupId = string.split(self._curTriggerRef.type,"=")[2]
        local endGroupId = self:GetEndGroupId()
        self._curTriggerRef = nil;
        local temp1 = 0
        local temp2 = 0
        temp1,temp2 = self:CheckTriggerStart(NewbieTriggerType.TriggerEvent,endGroupId)
        if(temp1 > 0 and temp2 > 0)then
            self:StartStory(temp2);
        end
        return
    end
    local config = GameTable.StorylineTriggerRef[id]
    self._curTriggerRef = config
    self:StartStory(config.parameter)
end
