function LxStoryCtrl:IsPassPlot(refId)
    local storyPassList = ModuleCenter.Story:GetPassEventIds()
    local evendId = 0
    for i, v in pairs(GameTable.StoryNewbieRef) do
        if(v.type == 5)then
            if(checknumber(v.parameter) == refId)then
                evendId = v.refId
            end
        end
    end
    if(evendId <= 0)then
        return false
    end
    for i, v in pairs(storyPassList) do
        if(v == evendId)then
            return true
        end
    end
    return false
end
