function LxStoryCtrl:Build1001SpecialCheck()
    local value = GameTable.StorylineConfigRef.spJump
    local levelData = string.split(value,"=")
    local level = checknumber(levelData[1])
    local buildData = ModuleCenter.Building:GetBuildingInfo(1001)
    if(buildData == nil)then
        return
    end
    if(level ~= buildData.level)then
        --等级不相等
        return
    end
    local equres = false

    if self._newbieView then
        local unitList = self._newbieView._unitList
        local stepData = string.split(levelData[2],"|")
        local steps = string.split(stepData[2],",")
        local stepList = {}
        for i, v in pairs(steps) do
            table.insert(stepList,checknumber(v))
        end
        for i, unit in pairs(unitList) do
            if(equres)then
                break
            end
            local unitId=  unit._eventId
            for i, step in pairs(stepList) do
                if(unitId == step)then
                    equres = true
                    break
                end
            end
        end
        if(equres == false)then
            return
        end
        ClosePanel(UiNames.BuildStove)
        ClosePanel(UiNames.BuildCreateTwo)
        self:GMDoStoryEvent(checknumber(stepData[3]))
    end

end
return LxStoryCtrl